SELECT 
FROM ScheduledTaskExecutions
WHERE task_id = #{taskId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT COUNT(*)
FROM ScheduledTaskExecutions
WHERE task_id = #{taskId}

SELECT 
FROM ScheduledTaskExecutions
WHERE task_id = #{taskId}
AND scheduled_time BETWEEN #{startTime} AND #{endTime}
ORDER BY scheduled_time DESC
